import React, { useState, useEffect } from 'react';
import { AppTab } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import HashtagGenerator from './components/HashtagGenerator';
import ImageGenerator from './components/ImageGenerator';
import Chatbot from './components/Chatbot';
import LiveSession from './components/LiveSession';
import BiometricSecurity from './components/BiometricSecurity';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [isInitializing, setIsInitializing] = useState(true);

  useEffect(() => {
    // Simulate initial system check
    const timer = setTimeout(() => setIsInitializing(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  if (isInitializing) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-slate-950">
        <div className="w-24 h-24 mb-8 relative">
           <div className="absolute inset-0 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin"></div>
           <div className="absolute inset-4 border-4 border-indigo-500 border-b-transparent rounded-full animate-spin-slow"></div>
        </div>
        <h1 className="text-3xl font-bold gold-text tracking-widest uppercase animate-pulse">
          ABA ROYAL ACCESS
        </h1>
        <p className="mt-4 text-slate-400 font-mono">Initializing Sovereign Neural Network...</p>
      </div>
    );
  }

  if (!isAuthorized) {
    return <BiometricSecurity onVerify={() => setIsAuthorized(true)} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.DASHBOARD:
        return <Dashboard />;
      case AppTab.HASHTAGS:
        return <HashtagGenerator />;
      case AppTab.IMAGES:
        return <ImageGenerator />;
      case AppTab.CHAT:
        return <Chatbot />;
      case AppTab.LIVE:
        return <LiveSession />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden text-slate-100">
      <Sidebar activeTab={activeTab} onTabChange={setActiveTab} />
      <main className="flex-1 overflow-y-auto p-4 md:p-8 relative">
        <div className="max-w-7xl mx-auto space-y-8">
          <header className="flex justify-between items-center border-b border-slate-800 pb-4">
            <div>
              <h2 className="text-2xl font-bold tracking-tight">
                {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} <span className="text-indigo-400">Control</span>
              </h2>
              <p className="text-slate-400 text-sm">System Status: <span className="text-emerald-400 font-mono">SOVEREIGN ACTIVE</span></p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex -space-x-2">
                <img src="https://picsum.photos/seed/aba1/40" className="w-10 h-10 rounded-full border-2 border-slate-900" alt="ABA" />
                <div className="w-10 h-10 rounded-full border-2 border-slate-900 bg-indigo-600 flex items-center justify-center text-xs font-bold">AL</div>
              </div>
              <div className="hidden md:block">
                <p className="text-sm font-semibold leading-none">King Abbas Aliyu</p>
                <p className="text-xs text-slate-500 mt-1">Sovereign Admin</p>
              </div>
            </div>
          </header>
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

