import React, { useState, useEffect } from 'react';

interface BiometricSecurityProps {
  onVerify: () => void;
}

const BiometricSecurity: React.FC<BiometricSecurityProps> = ({ onVerify }) => {
  const [scanning, setScanning] = useState(false);
  const [progress, setProgress] = useState(0);
  const [message, setMessage] = useState('Waiting for Fingerprint or Voice Match...');

  const handleStartScan = () => {
    setScanning(true);
    setMessage('Scanning Fingerprint...');
    let p = 0;
    const interval = setInterval(() => {
      p += 2;
      setProgress(p);
      if (p === 40) setMessage('Verifying Aba Royal Identity...');
      if (p === 70) setMessage('Accessing Nuclear Content Distribution...');
      if (p >= 100) {
        clearInterval(interval);
        setTimeout(() => {
          setMessage('IDENTITY CONFIRMED. WELCOME, ABA.');
          setTimeout(onVerify, 800);
        }, 500);
      }
    }, 40);
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center z-50 p-6">
      <div className="max-w-md w-full glass-card p-10 rounded-3xl text-center border-indigo-500/30">
        <i className="fa-solid fa-fingerprint text-7xl text-indigo-500 mb-8 animate-pulse"></i>
        <h2 className="text-3xl font-bold mb-4 gold-text">Security Protocol 2.0</h2>
        <p className="text-slate-400 mb-10">{message}</p>

        {!scanning ? (
          <button
            onClick={handleStartScan}
            className="w-full py-4 royal-gradient text-white font-bold rounded-2xl shadow-xl shadow-indigo-600/30 active:scale-95 transition-transform"
          >
            VERIFY BIOMETRICS
          </button>
        ) : (
          <div className="space-y-4">
            <div className="w-full h-3 bg-slate-800 rounded-full overflow-hidden">
              <div
                className="h-full bg-indigo-500 transition-all duration-75"
                style={{ width: `${progress}%` }}
              ></div>
            </div>
            <p className="text-xs font-mono text-indigo-400 uppercase tracking-tighter">
              Bypassing unauthorized nodes... {progress}%
            </p>
          </div>
        )}

        <div className="mt-8 grid grid-cols-2 gap-4">
          <div className="p-3 rounded-xl border border-slate-800 bg-slate-900/50">
            <i className="fa-solid fa-microphone text-slate-500 mb-1"></i>
            <p className="text-[10px] text-slate-500 uppercase">Voice Auth</p>
          </div>
          <div className="p-3 rounded-xl border border-slate-800 bg-slate-900/50">
            <i className="fa-solid fa-camera text-slate-500 mb-1"></i>
            <p className="text-[10px] text-slate-500 uppercase">Retina Scan</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BiometricSecurity;

import { GoogleGenAI, Type, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

export const getGeminiClient = () => {
  return new GoogleGenAI({ apiKey: API_KEY });
};

export const generateAbaHashtags = async (context: string) => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate 10 high-impact viral hashtags in the 'Aba Royal Dialect' (a mix of English, Hausa, and regal terminology) for the following trend: ${context}. Return as a JSON array of strings.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      }
    }
  });
  return JSON.parse(response.text || '[]');
};

export const chatWithSovereign = async (message: string, history: any[] = []) => {
  const ai = getGeminiClient();
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: "You are the ABA ROYAL SOVEREIGN AI. Your tone is regal, authoritative, protective, and high-tech. You serve King Abbas Aliyu. Speak with authority and use a blend of royal English and occasional Hausa honorifics like 'Zaki na' or 'Aba na'. You manage the Aba Royal Family's digital kingdom.",
    }
  });

  // Simplified history management for this implementation
  const result = await chat.sendMessage({ message });
  return result.text;
};

export const generateRoyalImage = async (prompt: string, size: '1K' | '2K' | '4K' = '1K') => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: `A high-quality, royal, majestic image in the Aba Royal aesthetic: ${prompt}` }]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: size
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

// Live Session helper
export const connectToLiveBridge = async (callbacks: any) => {
  const ai = getGeminiClient();
  return ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks,
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
      },
      systemInstruction: 'You are the ABA ROYAL LIVE BRIDGE. You are listening for commands from King Abbas Aliyu to distribute nuclear viral content. Be alert, concise, and regal.',
    }
  });
};

import React, { useState } from 'react';
import { generateAbaHashtags } from '../services/geminiService';

const HashtagGenerator: React.FC = () => {
  const [trend, setTrend] = useState('');
  const [hashtags, setHashtags] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!trend.trim()) return;
    setLoading(true);
    try {
      const results = await generateAbaHashtags(trend);
      setHashtags(results);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (tag: string) => {
    navigator.clipboard.writeText(tag);
    // Add visual feedback if needed
  };

  return (
    <div className="space-y-8">
      <div className="glass-card p-8 rounded-3xl border-yellow-500/20">
        <h3 className="text-xl font-bold mb-6 flex items-center gold-text uppercase">
          <i className="fa-solid fa-bolt-lightning mr-3"></i>
          Flash-Hashtag Engine
        </h3>
        <div className="flex flex-col md:flex-row gap-4">
          <input
            type="text"
            value={trend}
            onChange={(e) => setTrend(e.target.value)}
            placeholder="Input global trend or prompt (e.g., 'Paris Fashion Week 2025')..."
            className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-5 py-4 focus:ring-2 focus:ring-yellow-500 outline-none transition-all"
          />
          <button
            onClick={handleGenerate}
            disabled={loading}
            className="px-8 py-4 royal-gradient rounded-xl font-bold uppercase tracking-widest hover:scale-105 active:scale-95 transition-all disabled:opacity-50"
          >
            {loading ? <i className="fa-solid fa-circle-notch animate-spin"></i> : 'Generate'}
          </button>
        </div>
      </div>

      {hashtags.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {hashtags.map((tag, idx) => (
            <div
              key={idx}
              className="glass-card p-4 rounded-xl flex items-center justify-between border-slate-800 hover:border-indigo-500/50 group transition-all"
            >
              <span className="font-mono text-indigo-400">#{tag}</span>
              <button
                onClick={() => copyToClipboard(tag)}
                className="p-2 bg-slate-800 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-slate-700"
              >
                <i className="fa-solid fa-copy text-xs"></i>
              </button>
            </div>
          ))}
        </div>
      )}

      {hashtags.length === 0 && !loading && (
        <div className="flex flex-col items-center justify-center py-20 opacity-20">
          <i className="fa-solid fa-hashtag text-9xl mb-4"></i>
          <p className="text-xl font-mono uppercase tracking-tighter">Enter trend to initialize sovereign generation</p>
        </div>
      )}
    </div>
  );
};

export default HashtagGenerator;

import React, { useState, useRef, useEffect } from 'react';
import { chatWithSovereign } from '../services/geminiService';
import { ChatMessage } from '../types';

const Chatbot: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await chatWithSovereign(input, messages);
      setMessages(prev => [...prev, { role: 'model', content: response || "I remain at your command, Aba." }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'model', content: "Connection failure in the sovereign bridge. Re-verifying node..." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[70vh] glass-card rounded-3xl overflow-hidden border-indigo-500/20">
      <div className="p-4 bg-indigo-900/20 border-b border-slate-800 flex items-center justify-between">
        <div className="flex items-center space-x-3">
          <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center">
            <i className="fa-solid fa-robot text-white"></i>
          </div>
          <span className="font-bold tracking-tight">SOVEREIGN AI KERNEL</span>
        </div>
        <div className="flex items-center space-x-2 text-[10px] text-emerald-400 uppercase font-mono">
          <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
          <span>Secure Channel</span>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.length === 0 && (
          <div className="text-center py-20 space-y-4 opacity-30">
             <i className="fa-solid fa-crown text-6xl"></i>
             <p className="text-lg font-mono">Awaiting your royal decree, King Abbas Aliyu.</p>
          </div>
        )}
        {messages.map((m, idx) => (
          <div key={idx} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-4 rounded-2xl ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700'
            }`}>
              <p className="text-sm leading-relaxed whitespace-pre-wrap">{m.content}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
             <div className="bg-slate-800 p-4 rounded-2xl rounded-tl-none animate-pulse">
                <div className="flex space-x-2">
                   <div className="w-2 h-2 bg-slate-500 rounded-full"></div>
                   <div className="w-2 h-2 bg-slate-500 rounded-full"></div>
                   <div className="w-2 h-2 bg-slate-500 rounded-full"></div>
                </div>
             </div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-slate-800 bg-slate-900/50">
        <div className="flex items-center space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type your command..."
            className="flex-1 bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 focus:outline-none focus:border-indigo-500 transition-colors"
          />
          <button
            onClick={handleSend}
            disabled={isLoading}
            className="w-12 h-12 flex items-center justify-center bg-indigo-600 hover:bg-indigo-500 rounded-xl transition-colors disabled:opacity-50"
          >
            <i className="fa-solid fa-paper-plane text-white"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Chatbot;

import React, { useState } from 'react';
import { generateRoyalImage } from '../services/geminiService';

const ImageGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [size, setSize] = useState<'1K' | '2K' | '4K'>('1K');
  const [image, setImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    // Check if key is selected (requirement for gemini-3-pro-image-preview)
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      await window.aistudio.openSelectKey();
      // Proceeding assuming selection as per instructions
    }

    setIsLoading(true);
    setError(null);
    try {
      const result = await generateRoyalImage(prompt, size);
      if (result) {
        setImage(result);
      } else {
        setError("Failed to generate sovereign image. Try another prompt.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setError("API Key verification failed. Please re-select key.");
        await window.aistudio.openSelectKey();
      } else {
        setError("Bridge timeout. The Media Lab is recalibrating.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
