        <div className="glass-card p-8 rounded-3xl border-indigo-500/20">
          <h3 className="text-xl font-bold mb-6 flex items-center gold-text uppercase">
            <i className="fa-solid fa-wand-magic-sparkles mr-3"></i>
            Media Lab v2.0
          </h3>
          <div className="space-y-4">
            <div>
              <label className="text-xs font-bold text-slate-500 uppercase mb-2 block">Vision Prompt</label>
