              />
            </div>

            <div>
              <label className="text-xs font-bold text-slate-500 uppercase mb-2 block">Resolution Control</label>
              <div className="grid grid-cols-3 gap-2">
                {(['1K', '2K', '4K'] as const).map(s => (
                  <button
                    key={s}
                    onClick={() => setSize(s)}
