                  <i className="fa-solid fa-atom animate-spin mr-2"></i>
                  Synthesizing...
                </span>
              ) : 'Visualize Creation'}
            </button>
            {error && <p className="text-red-400 text-xs text-center font-mono uppercase">{error}</p>}
          </div>
        </div>

        <div className="glass-card p-6 rounded-3xl bg-indigo-950/20 border-slate-800">
           <h4 className="text-sm font-bold mb-2 gold-text">Aba Royal Aesthetic Rules</h4>
           <ul className="text-xs text-slate-400 space-y-2">
              <li className="flex items-start"><i className="fa-solid fa-check mr-2 mt-0.5 text-emerald-500"></i> High-contrast gold & indigo hues.</li>
